mkdir -p /tmp/binlog-reader && cd /tmp/binlog-reader && cat > Program.cs << 'CSHARP'
using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors and warnings
        var errors = new List<(string project, string code, string message, string file, int line)>();
        var warnings = new List<(string project, string code, string message, string file, int line)>();

        build.VisitAllChildren<Error>(error =>
        {
            var project = GetProjectName(error);
            errors.Add((project, error.Code ?? "", error.Text ?? error.ToString(), error.File ?? "", error.LineNumber));
        });

        build.VisitAllChildren<Warning>(warning =>
        {
            var project = GetProjectName(warning);
            warnings.Add((project, warning.Code ?? "", warning.Text ?? warning.ToString(), warning.File ?? "", warning.LineNumber));
        });

        Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
        foreach (var group in errors.GroupBy(e => e.project))
        {
            Console.WriteLine($"\n--- Project: {group.Key} ---");
            foreach (var e in group)
            {
                Console.WriteLine($"  [{e.code}] {e.file}:{e.line}");
                Console.WriteLine($"    {e.message}");
            }
        }

        Console.WriteLine($"\n=== WARNINGS ({warnings.Count}) ===");
        foreach (var group in warnings.GroupBy(w => w.project).Take(10))
        {
            Console.WriteLine($"\n--- Project: {group.Key} ---");
            foreach (var w in group.Take(20))
            {
                Console.WriteLine($"  [{w.code}] {w.file}:{w.line}");
                Console.WriteLine($"    {w.message}");
            }
            if (group.Count() > 20) Console.WriteLine($"  ... and {group.Count() - 20} more warnings");
        }

        // Show project dependency information
        Console.WriteLine("\n=== PROJECT BUILD ORDER & DEPENDENCIES ===");
        build.VisitAllChildren<Project>(project =>
        {
            var succeeded = project.Succeeded;
            if (!succeeded)
            {
                Console.WriteLine($"\nFAILED: {project.Name}");
            }
        });

        // Show failed targets
        Console.WriteLine("\n=== FAILED TARGETS ===");
        build.VisitAllChildren<Target>(target =>
        {
            if (!target.Succeeded)
            {
                var project = GetProjectName(target);
                Console.WriteLine($"  Target '{target.Name}' failed in {project}");
            }
        });
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p)
                return p.Name ?? "(unknown)";
            current = current.Parent;
        }
        return "(unknown)";
    }
}
